/* Aula 23 — modelJs: To-do list (estado + render + delegation + storage) */

const form = document.querySelector('#form');
const input = document.querySelector('#texto');
const erro = document.querySelector('#erro');
const lista = document.querySelector('#lista');

let tarefas = [];

// (extra) carregar do storage
try {
  tarefas = JSON.parse(localStorage.getItem('tarefas') || '[]');
} catch {
  tarefas = [];
}

function salvar() {
  localStorage.setItem('tarefas', JSON.stringify(tarefas));
}

function render() {
  lista.innerHTML = '';

  for (const t of tarefas) {
    const li = document.createElement('li');
    li.className = 'item';
    li.dataset.id = String(t.id);

    const span = document.createElement('span');
    span.className = 'text';
    span.textContent = t.texto;
    if (t.done) span.style.textDecoration = 'line-through';

    const btnDone = document.createElement('button');
    btnDone.type = 'button';
    btnDone.className = 'btn ghost done';
    btnDone.textContent = t.done ? 'Desfazer' : 'Concluir';

    const btnDel = document.createElement('button');
    btnDel.type = 'button';
    btnDel.className = 'btn danger del';
    btnDel.textContent = 'Excluir';

    li.append(span, btnDone, btnDel);
    lista.appendChild(li);
  }
}

function adicionar(texto) {
  tarefas.push({ id: Date.now(), texto, done: false });
  salvar();
  render();
}

function toggleDone(id) {
  const t = tarefas.find(x => x.id === id);
  if (t) {
    t.done = !t.done;
    salvar();
    render();
  }
}

function remover(id) {
  tarefas = tarefas.filter(x => x.id !== id);
  salvar();
  render();
}

// submit: adicionar
if (form && input && erro && lista) {
  form.addEventListener('submit', (e) => {
    e.preventDefault();
    erro.textContent = '';

    const texto = input.value.trim();
    if (!texto) {
      erro.textContent = 'Digite uma tarefa';
      return;
    }

    adicionar(texto);
    input.value = '';
    input.focus();
  });

  // delegation: concluir/excluir
  lista.addEventListener('click', (e) => {
    const item = e.target.closest('.item');
    if (!item) return;

    const id = Number(item.dataset.id);

    if (e.target.classList.contains('done')) {
      toggleDone(id);
      return;
    }

    if (e.target.classList.contains('del')) {
      remover(id);
      return;
    }
  });

  render();
}
